const CATEGORIES = ["Neurociencia y Neuroaprendizaje", "Currículum y Cultura Escolar", "Convivencia Escolar y Resolución de Conflictos", "Innovación Educativa y TIC", "Estilos de Aprendizaje y Enseñanza", "Violencia Intrafamiliar y de Género", "Gestión de Institutos y Servicio de Educación", "Educación Inclusiva y Modelo Sociocomunitario", "Motivación y Psicología Educativa", "Normativa Anticorrupción y Función Pública", "Fundamentos Generales de Educación"];

